void VideoPipeline::setMode(UpscaleMode mode){if(mode_==mode)return;Log::info(std::format("Upscale mode changed: {} -> {}",displayName(mode_),displayName(mode)));mode_=mode;}
void VideoPipeline::setComparison(bool enabled,UpscaleMode a,UpscaleMode b){comparisonEnabled_=enabled;comparisonA_=a;comparisonB_=b;Log::info(enabled?std::format("Comparison enabled: {} vs {}",displayName(a),displayName(b)):"Comparison disabled");}
