void VideoPipeline::saveScreenshot(FlightResources& f) {
    if (!f.readback.coherent) { const VkMappedMemoryRange r{VK_STRUCTURE_TYPE_MAPPED_MEMORY_RANGE,nullptr,f.readback.memory,0,VK_WHOLE_SIZE}; vkCheck(vkInvalidateMappedMemoryRanges(device_,1,&r),"invalidate screenshot"); }
    const auto& q=*f.screenshot; std::filesystem::create_directories(q.path.parent_path());
    const auto pixels=static_cast<std::size_t>(q.outputWidth)*q.outputHeight; const auto* halfA=static_cast<const std::uint16_t*>(f.readback.mapped); const auto* halfB=halfA+pixels*4;
    auto encode=[&](const std::uint16_t* source,std::vector<std::uint8_t>& target){target.resize(pixels*4);for(std::size_t i=0;i<pixels*4;++i){const float v=i%4==3?1:halfToFloat(source[i]);target[i]=static_cast<std::uint8_t>(std::lround(std::clamp(v,0.0F,1.0F)*255));}};
    auto write=[&](const std::filesystem::path& path,const std::vector<std::uint8_t>& data){const auto u=path.u8string();const std::string file(u.begin(),u.end());if(!stbi_write_png(file.c_str(),q.outputWidth,q.outputHeight,4,data.data(),q.outputWidth*4))throw std::runtime_error("Failed to save screenshot: "+path.string());};
    std::vector<std::uint8_t> rgbaA,rgbaB,final; encode(halfA,rgbaA);
    if(q.comparison){encode(halfB,rgbaB);final.resize(pixels*4);const int split=static_cast<int>(std::lround(q.divider*q.outputWidth));for(int y=0;y<q.outputHeight;++y)for(int x=0;x<q.outputWidth;++x){const auto i=(static_cast<std::size_t>(y)*q.outputWidth+x)*4;const auto& source=x<split?rgbaA:rgbaB;std::copy_n(source.data()+i,4,final.data()+i);}const auto stem=q.path.stem().string();write(q.path.parent_path()/(stem+"_A_"+std::string(toString(q.comparisonA))+".png"),rgbaA);write(q.path.parent_path()/(stem+"_B_"+std::string(toString(q.comparisonB))+".png"),rgbaB);}else final=std::move(rgbaA);write(q.path,final);
    std::ofstream m(q.metadataPath); m<<"{\n  \"input\": \""<<q.sourceFilename<<"\",\n  \"frameNumber\": "<<q.frame.frameNumber<<",\n  \"ptsSeconds\": "<<q.frame.ptsSeconds<<",\n  \"sourceResolution\": ["<<q.frame.width<<", "<<q.frame.height<<"],\n  \"outputResolution\": ["<<q.outputWidth<<", "<<q.outputHeight<<"],\n  \"framebufferResolution\": ["<<q.framebufferWidth<<", "<<q.framebufferHeight<<"],\n  \"mode\": \""<<(q.comparison?"comparison":toString(q.mode))<<"\",\n  \"casSharpness\": "<<q.sharpen.casSharpness<<",\n  \"rcasSharpness\": "<<q.sharpen.rcasSharpness<<",\n  \"antiRinging\": "<<(q.antiRinging?"true":"false")<<",\n  \"chromaMode\": \""<<toString(q.chromaMode)<<"\",\n  \"finalFilter\": \""<<toString(q.finalFilter)<<"\"";
    if(q.comparison)m<<",\n  \"comparisonA\": \""<<toString(q.comparisonA)<<"\",\n  \"comparisonB\": \""<<toString(q.comparisonB)<<"\",\n  \"divider\": "<<q.divider;
    if(q.timings){m<<",\n  \"gpuTimesMs\": {\n    \"reconstruction\": "<<q.timings->reconstructionMs<<",\n    \"postProcessing\": "<<q.timings->postProcessingMs<<",\n    \"total\": "<<q.timings->totalMs;constexpr std::array names{"nearest","bilinear","bicubic","lanczos2","cas","easu","rcas"};for(std::size_t i=0;i<q.timings->passes.size();++i)if(q.timings->passes[i])m<<",\n    \""<<names[i]<<"\": "<<*q.timings->passes[i];m<<"\n  }";}
    m<<"\n}\n"; Log::info("Saved screenshot: "+q.path.string());
}
